import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Asset {
  id: string;
  name: string;
  url: string;
  suffix: string;
}

export type SuffixType = 'px' | 'nx' | 'py' | 'ny' | 'pz' | 'nz';

import { Asset, SuffixType } from '../types';

const SUFFIXES: SuffixType[] = ['px', 'nx', 'py', 'ny', 'pz', 'nz'];

export const parseAndGenerateUrls = (inputUrl: string): Asset[] => {
  // Regex to match the pattern: .../2048-SUFFIX/FILENAME.EXT
  // Captures: 1: Prefix path, 2: existing suffix (e.g., px), 3: filename
  const regex = /^(.*\/)(\d+-)([pn][xyz])(\/.*)$/;
  const match = inputUrl.match(regex);

  if (!match) return [];

  const [_, prefix, baseSize, currentSuffix, filename] = match;

  return SUFFIXES.map((suffix) => ({
    id: `${baseSize}${suffix}`,
    name: `${baseSize.replace('-', '')}${suffix}`,
    suffix: suffix,
    url: `${prefix}${baseSize}${suffix}${filename}`
  }));
};

export const downloadFile = async (url: string, filename: string) => {
  try {
    const response = await fetch(url);
    const blob = await response.blob();
    const blobUrl = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = blobUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(blobUrl);
  } catch (error) {
    console.error('Download failed:', error);
    // Fallback to direct link opening if CORS prevents fetch
    window.open(url, '_blank');
  }
};

import React from 'react';
