import React, { useState, useEffect, useMemo } from 'react';
import { Search, Download, Trash2, Github, Image as ImageIcon, Loader2 } from 'lucide-react';
import { Asset } from './types';
import { parseAndGenerateUrls, downloadFile } from './utils/urlHelper';
import ImageCard from './components/ImageCard';

// Using JSZip for batch downloads
// Note: In a real environment, you'd install this via npm. 
// For this single-file output, we'll assume it's available or handle sequential downloads as fallback.
declare var JSZip: any;

const App: React.FC = () => {
  const [url, setUrl] = useState('');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [isDownloadingAll, setIsDownloadingAll] = useState(false);
  const [isJszipLoaded, setIsJszipLoaded] = useState(false);

  // Dynamically load JSZip for batch download functionality
  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
    script.async = true;
    script.onload = () => setIsJszipLoaded(true);
    document.body.appendChild(script);
  }, []);

  const handleProcessUrl = (e: React.FormEvent) => {
    e.preventDefault();
    if (!url.trim()) return;

    const generated = parseAndGenerateUrls(url.trim());
    if (generated.length > 0) {
      setAssets(generated);
    } else {
      alert("Invalid URL format. Expected pattern like: .../2048-px/filename.jpeg");
    }
  };

  const handleDownloadAll = async () => {
    if (assets.length === 0) return;
    setIsDownloadingAll(true);

    if (isJszipLoaded && typeof JSZip !== 'undefined') {
      try {
        const zip = new JSZip();
        const promises = assets.map(async (asset) => {
          const response = await fetch(asset.url);
          const blob = await response.blob();
          zip.file(`${asset.name}.jpeg`, blob);
        });

        await Promise.all(promises);
        const content = await zip.generateAsync({ type: 'blob' });
        const blobUrl = window.URL.createObjectURL(content);
        const link = document.createElement('a');
        link.href = blobUrl;
        link.download = `skybox_assets_${Date.now()}.zip`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        window.URL.revokeObjectURL(blobUrl);
      } catch (error) {
        console.error('Batch download failed:', error);
        alert('Could not create ZIP. Falling back to individual downloads...');
        // Fallback: Sequential download
        for (const asset of assets) {
          await downloadFile(asset.url, `${asset.name}.jpeg`);
          await new Promise(resolve => setTimeout(resolve, 300));
        }
      }
    } else {
      // Manual fallback if JSZip didn't load
      for (const asset of assets) {
        await downloadFile(asset.url, `${asset.name}.jpeg`);
        await new Promise(resolve => setTimeout(resolve, 300));
      }
    }

    setIsDownloadingAll(false);
  };

  const clearAll = () => {
    setAssets([]);
    setUrl('');
  };

  return (
    <div className="min-h-screen pb-20 px-4 md:px-8">
      {/* Header */}
      <header className="max-w-6xl mx-auto py-12 flex flex-col items-center text-center">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center mb-6 shadow-xl shadow-blue-500/20">
          <ImageIcon className="text-white" size={32} />
        </div>
        <h1 className="text-4xl md:text-5xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
          Asset Generator
        </h1>
        <p className="mt-4 text-slate-400 max-w-lg text-lg">
          Paste a single cube-map URL to automatically generate all 6 axis variations (px, nx, py, ny, pz, nz).
        </p>
      </header>

      {/* Control Panel */}
      <main className="max-w-6xl mx-auto">
        <div className="bg-slate-800/50 backdrop-blur-xl border border-slate-700 p-2 md:p-3 rounded-2xl shadow-2xl mb-12">
          <form onSubmit={handleProcessUrl} className="flex flex-col md:flex-row gap-3">
            <div className="relative flex-grow group">
              <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none">
                <Search size={20} className="text-slate-500 group-focus-within:text-blue-400 transition-colors" />
              </div>
              <input
                type="url"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="https://platform-resources-staging.s3.../2048-px/image.jpeg"
                className="w-full bg-slate-900/50 border border-slate-700 rounded-xl py-4 pl-12 pr-4 text-slate-200 placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all"
                required
              />
            </div>
            <button
              type="submit"
              className="bg-blue-600 hover:bg-blue-500 text-white font-semibold py-4 px-8 rounded-xl transition-all shadow-lg shadow-blue-600/20 active:scale-95 flex items-center justify-center gap-2"
            >
              Generate Assets
            </button>
          </form>
        </div>

        {/* Results Area */}
        {assets.length > 0 && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 border-b border-slate-800 pb-6">
              <div className="flex items-center gap-3">
                <div className="bg-green-500/10 text-green-400 px-3 py-1 rounded-full text-sm font-medium border border-green-500/20">
                  {assets.length} Assets Found
                </div>
                <button 
                  onClick={clearAll}
                  className="flex items-center gap-2 text-slate-400 hover:text-red-400 transition-colors text-sm px-3 py-1"
                >
                  <Trash2 size={16} />
                  Clear
                </button>
              </div>

              <button
                onClick={handleDownloadAll}
                disabled={isDownloadingAll}
                className="w-full sm:w-auto bg-slate-100 hover:bg-white text-slate-900 font-bold py-3 px-8 rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg disabled:opacity-50 disabled:cursor-not-allowed active:scale-95"
              >
                {isDownloadingAll ? (
                  <>
                    <Loader2 className="animate-spin" size={20} />
                    Processing...
                  </>
                ) : (
                  <>
                    <Download size={20} />
                    Download All (.zip)
                  </>
                )}
              </button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {assets.map((asset) => (
                <ImageCard key={asset.id} asset={asset} />
              ))}
            </div>
          </div>
        )}

        {/* Empty State */}
        {assets.length === 0 && (
          <div className="py-20 flex flex-col items-center justify-center text-slate-600 border-2 border-dashed border-slate-800 rounded-3xl">
            <div className="p-4 bg-slate-900 rounded-full mb-4">
              <ImageIcon size={40} />
            </div>
            <p className="text-lg">No assets generated yet</p>
            <p className="text-sm">Enter a valid S3 image URL to begin</p>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="max-w-6xl mx-auto mt-20 pt-8 border-t border-slate-800 flex flex-col md:flex-row items-center justify-between gap-4 text-slate-500 text-sm">
        <p>&copy; {new Date().getFullYear()} Skybox Tool. Built for visual consistency.</p>
        <div className="flex items-center gap-6">
          <a href="#" className="hover:text-blue-400 transition-colors">Documentation</a>
          <a href="#" className="hover:text-blue-400 transition-colors">API Reference</a>
          <a href="#" className="flex items-center gap-1 hover:text-white transition-colors">
            <Github size={16} />
            Source
          </a>
        </div>
      </footer>
    </div>
  );
};

export default App;
